module top_module(
    /* Input ports */
    input [7:0] in,
    /* Output ports */
    output reg [3:0] out
);integer i;
reg [3:0] unused_count;

always @ (*) begin
    unused_count = 0;
    for (i = 0; i < 8; i = i + 1) begin
        if (in[i] == 1) begin
            unused_count = unused_count + 1;
        end
    end
    out = unused_count;
end

endmodule
